  1→import GuestLayout from '@/Layouts/GuestLayout';
  2→import { Head, Link, useForm } from '@inertiajs/react';
  3→import { cn } from '@/lib/utils';
  4→import { Button } from '@/Components/ui/button';
  5→import { Input } from '@/Components/ui/input';
  6→import { Label } from '@/Components/ui/label';
  7→import { FormEventHandler } from 'react';
  8→
  9→export default function Login({
 10→    status,
 11→    canResetPassword,
 12→}: {
 13→    status?: string;
 14→    canResetPassword: boolean;
 15→}) {
 16→    const { data, setData, post, processing, errors, reset } = useForm({
 17→        email: '',
 18→        password: '',
 19→        remember: false as boolean,
 20→    });
 21→
 22→    const submit: FormEventHandler = (e) => {
 23→        e.preventDefault();
 24→
 25→        post(route('login'), {
 26→            onFinish: () => reset('password'),
 27→        });
 28→    };
 29→
 30→    return (
 31→        <GuestLayout>
 32→            <Head title="Sign In" />
 33→
 34→            <h2 className={cn('text-xl font-semibold text-foreground mb-6')}>Sign In</h2>
 35→
 36→            {status && (
 37→                <div className={cn('mb-4 text-sm font-medium text-green-600')}>
 38→                    {status}
 39→                </div>
 40→            )}
 41→
 42→            <form onSubmit={submit} className={cn('space-y-4')}>
 43→                <div className={cn('space-y-2')}>
 44→                    <Label htmlFor="email">Email</Label>
 45→                    <Input
 46→                        id="email"
 47→                        type="email"
 48→                        value={data.email}
 49→                        autoComplete="username"
 50→                        autoFocus
 51→                        onChange={(e) => setData('email', e.target.value)}
 52→                    />
 53→                    {errors.email && (
 54→                        <p className={cn('text-sm text-destructive')}>{errors.email}</p>
 55→                    )}
 56→                </div>
 57→
 58→                <div className={cn('space-y-2')}>
 59→                    <Label htmlFor="password">Password</Label>
 60→                    <Input
 61→                        id="password"
 62→                        type="password"
 63→                        value={data.password}
 64→                        autoComplete="current-password"
 65→                        onChange={(e) => setData('password', e.target.value)}
 66→                    />
 67→                    {errors.password && (
 68→                        <p className={cn('text-sm text-destructive')}>{errors.password}</p>
 69→                    )}
 70→                </div>
 71→
 72→                <div className={cn('flex items-center')}>
 73→                    <input
 74→                        id="remember"
 75→                        type="checkbox"
 76→                        checked={data.remember}
 77→                        onChange={(e) => setData('remember', e.target.checked)}
 78→                        className={cn('size-4 rounded border-input text-brand-orange accent-brand-orange')}
 79→                    />
 80→                    <Label htmlFor="remember" className={cn('ml-2 text-sm text-muted-foreground')}>
 81→                        Remember me
 82→                    </Label>
 83→                </div>
 84→
 85→                <div className={cn('flex items-center justify-between pt-2')}>
 86→                    {canResetPassword && (
 87→                        <Link
 88→                            href={route('password.request')}
 89→                            className={cn('text-sm text-muted-foreground hover:text-foreground')}
 90→                        >
 91→                            Forgot your password?
 92→                        </Link>
 93→                    )}
 94→
 95→                    <Button
 96→                        type="submit"
 97→                        disabled={processing}
 98→                        className={cn('bg-brand-orange text-white hover:bg-brand-orange/90 ml-auto')}
 99→                    >
100→                        Sign In
101→                    </Button>
102→                </div>
103→
104→                <p className={cn('text-center text-sm text-muted-foreground')}>
105→                    Don't have an account?{' '}
106→                    <Link href={route('register')} className={cn('text-brand-orange hover:underline')}>
107→                        Sign Up
108→                    </Link>
109→                </p>
110→            </form>
111→        </GuestLayout>
112→    );
113→}
