  1→import { useState } from 'react';
  2→import { useForm, useFieldArray } from 'react-hook-form';
  3→import { zodResolver } from '@hookform/resolvers/zod';
  4→import { cn } from '@/lib/utils';
  5→import { roomSchema, type RoomFormValues } from '@/lib/schemas';
  6→import { useBookingStore } from '@/Stores/useBookingStore';
  7→import { calculateNights, calculatePrice } from '@/lib/utils/calculatePrice';
  8→import { formatCurrency } from '@/lib/utils/formatCurrency';
  9→import { Button } from '@/Components/ui/button';
 10→import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/Components/ui/card';
 11→import { Label } from '@/Components/ui/label';
 12→import { Badge } from '@/Components/ui/badge';
 13→import { Separator } from '@/Components/ui/separator';
 14→import { MinusIcon, PlusIcon, UsersIcon, ChevronDownIcon, ChevronUpIcon } from 'lucide-react';
 15→import { ImageCarousel } from './ImageCarousel';
 16→import type { PropertyData, Unit } from '@/types/property';
 17→
 18→interface RoomStepProps {
 19→  propertyData: PropertyData;
 20→}
 21→
 22→export function RoomStep({ propertyData }: RoomStepProps) {
 23→  const { checkIn, checkOut, rooms: storedRooms, setRooms, nextStep, prevStep } = useBookingStore();
 24→  const { units, property } = propertyData;
 25→  const nights = checkIn && checkOut ? calculateNights(checkIn, checkOut) : 0;
 26→
 27→  // Track which cards have the per-room guest section expanded
 28→  const [expandedGuests, setExpandedGuests] = useState<Record<number, boolean>>({});
 29→
 30→  const defaultRooms = units.map((unit) => {
 31→    const existing = storedRooms.find((r) => r.unitId === unit.id);
 32→    if (existing) {
 33→      return {
 34→        unitId: unit.id,
 35→        quantity: existing.quantity,
 36→        guests: existing.guests,
 37→        guestsPerRoom: existing.guestsPerRoom ?? Array(existing.quantity).fill(
 38→          Math.max(1, Math.floor(existing.guests / existing.quantity))
 39→        ),
 40→      };
 41→    }
 42→    return { unitId: unit.id, quantity: 0, guests: 0, guestsPerRoom: [] as number[] };
 43→  });
 44→
 45→  const {
 46→    control,
 47→    handleSubmit,
 48→    watch,
 49→    setValue,
 50→    formState: { errors },
 51→  } = useForm<RoomFormValues>({
 52→    resolver: zodResolver(roomSchema),
 53→    defaultValues: { rooms: defaultRooms },
 54→  });
 55→
 56→  const { fields } = useFieldArray({ control, name: 'rooms' });
 57→  const watchedRooms = watch('rooms');
 58→
 59→  const breakdown = calculatePrice(watchedRooms, units, nights, property.tax_rate);
 60→
 61→  const onSubmit = (data: RoomFormValues) => {
 62→    const filtered = data.rooms
 63→      .filter((r) => r.quantity > 0)
 64→      .map((r) => ({
 65→        ...r,
 66→        guests: r.guestsPerRoom?.reduce((sum, g) => sum + g, 0) ?? r.guests,
 67→      }));
 68→    setRooms(filtered);
 69→    nextStep();
 70→  };
 71→
 72→  const handleQuantityChange = (index: number, delta: number, unit: Unit) => {
 73→    const current = watchedRooms[index].quantity;
 74→    const newQty = Math.max(0, Math.min(current + delta, unit.available_count));
 75→    const currentPerRoom = watchedRooms[index].guestsPerRoom ?? [];
 76→
 77→    setValue(`rooms.${index}.quantity`, newQty, { shouldValidate: true });
 78→
 79→    if (newQty === 0) {
 80→      setValue(`rooms.${index}.guests`, 0);
 81→      setValue(`rooms.${index}.guestsPerRoom`, []);
 82→      setExpandedGuests((prev) => ({ ...prev, [index]: false }));
 83→    } else if (newQty > current) {
 84→      // Adding rooms - append with 1 guest each
 85→      const newPerRoom = [...currentPerRoom, ...Array(newQty - current).fill(1)];
 86→      setValue(`rooms.${index}.guestsPerRoom`, newPerRoom);
 87→      setValue(`rooms.${index}.guests`, newPerRoom.reduce((s, g) => s + g, 0));
 88→    } else if (newQty < current) {
 89→      // Removing rooms - trim from end
 90→      const newPerRoom = currentPerRoom.slice(0, newQty);
 91→      setValue(`rooms.${index}.guestsPerRoom`, newPerRoom);
 92→      setValue(`rooms.${index}.guests`, newPerRoom.reduce((s, g) => s + g, 0));
 93→    }
 94→
 95→    // If going from 0 to 1, initialize
 96→    if (current === 0 && newQty > 0) {
 97→      const newPerRoom = Array(newQty).fill(1);
 98→      setValue(`rooms.${index}.guestsPerRoom`, newPerRoom);
 99→      setValue(`rooms.${index}.guests`, newQty);
100→    }
101→  };
102→
103→  const handlePerRoomGuestChange = (roomIndex: number, guestIndex: number, delta: number, unit: Unit) => {
104→    const perRoom = [...(watchedRooms[roomIndex].guestsPerRoom ?? [])];
105→    const current = perRoom[guestIndex] ?? 1;
106→    perRoom[guestIndex] = Math.max(1, Math.min(current + delta, unit.max_guests));
107→    setValue(`rooms.${roomIndex}.guestsPerRoom`, perRoom);
108→    setValue(`rooms.${roomIndex}.guests`, perRoom.reduce((s, g) => s + g, 0));
109→  };
110→
111→  const toggleExpanded = (index: number) => {
112→    setExpandedGuests((prev) => ({ ...prev, [index]: !prev[index] }));
113→  };
114→
115→  return (
116→    <form onSubmit={handleSubmit(onSubmit)} className={cn('space-y-6')}>
117→      <h2 className={cn('text-xl font-semibold')}>Select your rooms</h2>
118→
119→      {errors.rooms?.root && (
120→        <p className={cn('text-sm text-destructive')} role="alert">
121→          {errors.rooms.root.message}
122→        </p>
123→      )}
124→
125→      <div className={cn('grid grid-cols-1 gap-4 md:grid-cols-2')}>
126→        {fields.map((field, index) => {
127→          const unit = units.find((u) => u.id === field.unitId);
128→          if (!unit) return null;
129→
130→          const qty = watchedRooms[index]?.quantity ?? 0;
131→          const perRoom = watchedRooms[index]?.guestsPerRoom ?? [];
132→          const totalGuests = perRoom.reduce((s, g) => s + g, 0);
133→          const isExpanded = expandedGuests[index] ?? false;
134→
135→          // Calculate line total for this room
136→          const lineTotal =
137→            unit.pricing_model === 'per_unit'
138→              ? unit.price * nights * qty
139→              : unit.price * totalGuests * nights;
140→
141→          return (
142→            <Card key={field.id} className={cn('pt-0')}>
143→              <ImageCarousel
144→                images={unit.pictures}
145→                alt={unit.name}
146→                className={cn('h-40')}
147→              />
148→              <CardHeader>
149→                <div className={cn('flex items-start justify-between')}>
150→                  <CardTitle>{unit.name}</CardTitle>
151→                  <Badge variant="secondary">
152→                    {unit.available_count} available
153→                  </Badge>
154→                </div>
155→                <CardDescription>
156→                  {formatCurrency(unit.price)}{' '}
157→                  {unit.pricing_model === 'per_unit'
158→                    ? 'per room / night'
159→                    : 'per person / night'}
160→                  {' - '}Up to {unit.max_guests}{' '}
161→                  {unit.max_guests === 1 ? 'guest' : 'guests'}
162→                </CardDescription>
163→              </CardHeader>
164→              <CardContent className={cn('space-y-4')}>
165→                {/* Quantity selector */}
166→                <div className={cn('space-y-2')}>
167→                  <Label>Rooms</Label>
168→                  <div className={cn('flex items-center gap-3')}>
169→                    <Button
170→                      type="button"
171→                      variant="outline"
172→                      size="icon"
173→                      className={cn('min-h-11 min-w-11')}
174→                      onClick={() => handleQuantityChange(index, -1, unit)}
175→                      disabled={qty === 0}
176→                      aria-label={`Decrease ${unit.name} quantity`}
177→                    >
178→                      <MinusIcon className={cn('h-4 w-4')} />
179→                    </Button>
180→                    <span
181→                      className={cn('w-8 text-center text-lg font-medium')}
182→                      aria-live="polite"
183→                      aria-label={`${qty} ${unit.name} rooms selected`}
184→                    >
185→                      {qty}
186→                    </span>
187→                    <Button
188→                      type="button"
189→                      variant="outline"
190→                      size="icon"
191→                      className={cn('min-h-11 min-w-11')}
192→                      onClick={() => handleQuantityChange(index, 1, unit)}
193→                      disabled={qty >= unit.available_count}
194→                      aria-label={`Increase ${unit.name} quantity`}
195→                    >
196→                      <PlusIcon className={cn('h-4 w-4')} />
197→                    </Button>
198→                  </div>
199→                </div>
200→
201→                {/* Guest section - shown when quantity > 0 */}
202→                {qty > 0 && (
203→                  <div className={cn('space-y-3')}>
204→                    {/* Summary row with customize toggle */}
205→                    <button
206→                      type="button"
207→                      onClick={() => qty > 1 ? toggleExpanded(index) : undefined}
208→                      className={cn(
209→                        'flex w-full items-center justify-between rounded-md bg-muted px-3 py-2 text-sm',
210→                        qty > 1 && 'cursor-pointer hover:bg-muted/80'
211→                      )}
212→                    >
213→                      <span className={cn('flex items-center gap-1.5')}>
214→                        <UsersIcon className={cn('h-4 w-4 text-muted-foreground')} />
215→                        <span className={cn('font-medium')}>
216→                          {totalGuests} {totalGuests === 1 ? 'guest' : 'guests'} total
217→                        </span>
218→                      </span>
219→                      {qty > 1 && (
220→                        <span className={cn('flex items-center gap-1 text-xs text-muted-foreground')}>
221→                          Customize
222→                          {isExpanded ? (
223→                            <ChevronUpIcon className={cn('h-3.5 w-3.5')} />
224→                          ) : (
225→                            <ChevronDownIcon className={cn('h-3.5 w-3.5')} />
226→                          )}
227→                        </span>
228→                      )}
229→                    </button>
230→
231→                    {/* Single room - inline stepper (no expand needed) */}
232→                    {qty === 1 && (
233→                      <div className={cn('flex items-center gap-3')}>
234→                        <Label className={cn('text-sm text-muted-foreground')}>Guests</Label>
235→                        <Button
236→                          type="button"
237→                          variant="outline"
238→                          size="icon"
239→                          className={cn('h-8 w-8')}
240→                          onClick={() => handlePerRoomGuestChange(index, 0, -1, unit)}
241→                          disabled={(perRoom[0] ?? 1) <= 1}
242→                          aria-label="Decrease guests"
243→                        >
244→                          <MinusIcon className={cn('h-3 w-3')} />
245→                        </Button>
246→                        <span className={cn('w-6 text-center text-sm font-medium')}>
247→                          {perRoom[0] ?? 1}
248→                        </span>
249→                        <Button
250→                          type="button"
251→                          variant="outline"
252→                          size="icon"
253→                          className={cn('h-8 w-8')}
254→                          onClick={() => handlePerRoomGuestChange(index, 0, 1, unit)}
255→                          disabled={(perRoom[0] ?? 1) >= unit.max_guests}
256→                          aria-label="Increase guests"
257→                        >
258→                          <PlusIcon className={cn('h-3 w-3')} />
259→                        </Button>
260→                      </div>
261→                    )}
262→
263→                    {/* Multiple rooms - expandable per-room controls */}
264→                    {qty > 1 && isExpanded && (
265→                      <div className={cn('space-y-2 rounded-md border p-3')}>
266→                        {perRoom.map((guestCount, gi) => (
267→                          <div key={gi} className={cn('flex items-center justify-between')}>
268→                            <span className={cn('text-sm text-muted-foreground')}>
269→                              Room {gi + 1}
270→                            </span>
271→                            <div className={cn('flex items-center gap-2')}>
272→                              <Button
273→                                type="button"
274→                                variant="outline"
275→                                size="icon"
276→                                className={cn('h-7 w-7')}
